ALTER TABLE OFERTAS_IGREJAS ADD CONSTRAINT OFERTAS_IGREJAS_IBFK_1 FOREIGN KEY (OFERTA_ID) REFERENCES OFERTAS (ID) ON DELETE CASCADE;
ALTER TABLE OFERTAS_IGREJAS ADD CONSTRAINT OFERTAS_IGREJAS_IBFK_2 FOREIGN KEY (COD_IGREJA) REFERENCES IGREJAS (COD_IGREJA) ON DELETE CASCADE;
