ALTER TABLE SUBGRUPO_PROJETO ADD CONSTRAINT SUBGRUPO_PROJETO_IBFK_2 FOREIGN KEY (SUBGRUPO_ID) REFERENCES PROJETO (PROJETO_ID) ON DELETE CASCADE;
